def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                counter = 0
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    trig = np.sin(ratio * b / (a + 0.9)) + np.cos(ratio * a * b * 0.1)
                    if (a + b) % 2 == 0:
                        priority += val * trig * 1.3
                    else:
                        priority -= val * trig * 0.8
                    counter += b
                priority += np.exp(counter * 0.01) * np.tanh(ratio - 7)
            priority += (np.log(ratio) * np.sin(ratio * 2.2)) ** 2
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * q) / (q + 0.3)
                    if p % 2 == 0:
                        priority += np.tanh(term) * 1.8
                    else:
                        priority -= np.tanh(term) * 1.2
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 4) * 3.5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 0.9)
            priority = (s * np.cos(9 * ratio)) - np.log1p(ratio) * 8 + np.tanh(5 * (4 - ratio)) * 2.3
            for z in range(1, 6):
                priority += np.sin(z * ratio * i * 0.5) * ((ratio - 2) ** z) / z * 0.7
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 1.5 + 0.3)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.3) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 25):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.8) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.2)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.1
            else:
                priority -= np.exp(-ratio * 1.7) * 4.2
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6.2
            else:
                priority -= np.exp(-ratio * 2.3) * 5.1
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7.1
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.6
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.25) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.25) * 0.7
        if i % 2 == 0 and ratio > 1.2:
            for w in range(1, 4):
                priority += np.tanh((ratio - 1.2) ** w) * np.sin(i * w * 0.4)
        priorities[i] = priority
    return priorities
